// script.js — PulseSync Shared Utilities
// Add any global helper functions here that are shared across multiple pages.

/**
 * Formats a date string (YYYY-MM-DD) to a human-readable format.
 * @param {string} dateStr - ISO date string
 * @returns {string} - e.g. "14 Apr 2026"
 */
function formatDateGlobal(dateStr) {
    if (!dateStr) return '--';
    return new Date(dateStr).toLocaleDateString('en-IN', {
        day: '2-digit', month: 'short', year: 'numeric'
    });
}

